import React from 'react';
import './battle-mode.css'
class BattleMode extends React.Component {
	handleCloseBattle = () => {

	// Call the function passed from the parent component
    if (this.props.onCloseBattle) {
		this.props.onCloseBattle();
	  }
};


  render() {
    return (
      <div className="battle-mode">
        <h2>Battle Mode</h2>
        {/* Add your battle UI and logic here */}
        <button onClick={this.handleCloseBattle}>Close Battle</button>
      </div>
    );
  }
}

export default BattleMode;
